class Ledger:
    """
    Lightweight in-memory ledger.
    Accounts are stored as a mapping from account IDs (hashable) to Decimal balances.
    """

    def __init__(self, initial_accounts: Optional[Dict[str, Decimal]] = None):
        self._accounts: Dict[str, Decimal] = (
            {k: self._to_decimal(v) for k, v in initial_accounts.items()}
            if initial_accounts
            else {}
        )

    # --------------------------------------------------------------------- #
    # Public API
    # --------------------------------------------------------------------- #
    @property
    def accounts(self) -> Dict[str, Decimal]:
        return dict(self._accounts)

    def add_account(self, account_id: str, opening_balance=Decimal("0")) -> None:
        if account_id in self._accounts:
            raise InvalidTransaction(f"Account '{account_id}' already exists")
        self._accounts[account_id] = self._to_decimal(opening_balance)

    def process(self, transactions: Iterable[Dict]) -> Tuple[List[Dict], List[Tuple[Dict, TransactionError]]]:
        """
        Execute transactions atomically (best-effort). Returns two lists:
            1. successful transactions in commit order
            2. (transaction, error) tuples for those that failed
        Valid transaction dict forms:
            {'type': 'deposit',  'to':   acct,        'amount': x}
            {'type': 'withdraw', 'from': acct,        'amount': x}
            {'type': 'transfer', 'from': acct_from,   'to': acct_to, 'amount': x}
        Amount must be positive.
        """
        successes: List[Dict] = []
        failures: List[Tuple[Dict, TransactionError]] = []

        for tx in transactions:
            try:
                self._apply(tx)
            except TransactionError as exc:
                failures.append((tx, exc))
            else:
                successes.append(tx)

        return successes, failures

    # --------------------------------------------------------------------- #
    # Internal helpers
    # --------------------------------------------------------------------- #
    def _apply(self, tx: Dict) -> None:
        if "type" not in tx:
            raise InvalidTransaction("Missing 'type' field")

        ttype = tx["type"].lower()
        amount = self._to_decimal(tx.get("amount"))

        if amount <= 0:
            raise InvalidTransaction("Amount must be positive")

        if ttype == "deposit":
            acct = tx.get("to")
            self._credit(acct, amount)

        elif ttype == "withdraw":
            acct = tx.get("from")
            self._debit(acct, amount)

        elif ttype == "transfer":
            src = tx.get("from")
            dst = tx.get("to")
            self._debit(src, amount)
            self._credit(dst, amount)
        else:
            raise InvalidTransaction(f"Unsupported type '{ttype}'")

    def _credit(self, account_id: str, amount: Decimal) -> None:
        if account_id not in self._accounts:
            raise UnknownAccount(account_id)
        self._accounts[account_id] += amount

    def _debit(self, account_id: str, amount: Decimal) -> None:
        if account_id not in self._accounts:
            raise UnknownAccount(account_id)
        if self._accounts[account_id] < amount:
            raise InsufficientFunds(f"{account_id} has insufficient funds")
        self._accounts[account_id] -= amount

    @staticmethod
    def _to_decimal(value) -> Decimal:
        if isinstance(value, Decimal):
            return value
        try:
            return Decimal(str(value))
        except Exception as exc:
            raise InvalidTransaction(f"Invalid numeric value '{value}'") from exc


